INSERT INTO taller_1.pagina_contenidos (pagina,clave,titulo,valor,created_at,updated_at) VALUES
	 ('quienes_somos','quienes_somos_principal_titulo','Quiénes Somos - Título Principal','¿Quiénes Somos?','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('quienes_somos','quienes_somos_principal_texto','Quiénes Somos - Texto Principal','Nacimos de la pasión por el deporte en Corrientes. En ENERGY, profesionalizamos la nutrición deportiva para que alcances tus metas de forma segura y constante. Sabemos que detrás de cada entrenamiento hay un objetivo claro, y estamos acá para darte el combustible exacto que necesitás para superar.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('quienes_somos','quienes_somos_calidad_titulo','Quiénes Somos - Calidad Título','Calidad Premium','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('quienes_somos','quienes_somos_calidad_texto1','Quiénes Somos - Calidad Párrafo 1','Trabajamos exclusivamente con laboratorios certificados y marcas líderes en el rubro de la nutrición deportiva. Entendemos que alcanzar tu mejor versión requiere dedicación, y por ello, tu salud es nuestra máxima prioridad. Cada suplemento que sale de nuestra tienda ha sido seleccionado bajo los más estrictos estándares de calidad, garantizando que recibas fórmulas puras, seguras y respaldadas por la ciencia.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('quienes_somos','quienes_somos_calidad_texto2','Quiénes Somos - Calidad Párrafo 2','Nuestro equipo se encarga de auditar constantemente el origen y la originalidad de todo nuestro stock. Al elegirnos, no solo estás comprando un producto, sino que estás invirtiendo en la tranquilidad de saber que consumís suplementación con sellos de autenticidad verificados, fechas de caducidad controladas y el respaldo de una tienda que se toma tu rendimiento tan en serio como vos.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('quienes_somos','quienes_somos_energia_titulo','Quiénes Somos - Energía Título','Máxima Energía','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('quienes_somos','quienes_somos_energia_texto','Quiénes Somos - Energía Texto','Entendemos lo que tu cuerpo necesita para que potencies tu rendimiento en cada repetición. Nuestro diferencial es simple: no solo vendemos, te asesoramos. Ya con la garantía de estar consumiendo lo mejor, nuestro equipo se enfoca en escucharte. Entendemos tus metas, ya sea ganar masa muscular o acelerar tu recuperación, y te guiamos para elegir exactamente lo que tu metabolismo exige para romper tus propios límites.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_titulo','Comercialización - Título Principal','CÓMO COMPRAR','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_subtitulo','Comercialización - Subtítulo','Tu suplementación favorita en la puerta de tu casa. Rápido, seguro y garantizado.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_paso1_titulo','Comercialización - Paso 1 Título','Elegí tus productos','2026-05-28 16:49:30','2026-05-28 16:49:30');
INSERT INTO taller_1.pagina_contenidos (pagina,clave,titulo,valor,created_at,updated_at) VALUES
	 ('comercializacion','comercializacion_paso1_desc','Comercialización - Paso 1 Descripción','Navegá por nuestro catálogo y seleccioná los suplementos que mejor se adapten a tu objetivo físico.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_paso2_titulo','Comercialización - Paso 2 Título','Coordiná el pago','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_paso2_desc','Comercialización - Paso 2 Descripción','Aceptamos transferencias, tarjetas de crédito/débito y pagos en efectivo al momento de la entrega.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_paso3_titulo','Comercialización - Paso 3 Título','Recibí y entrená','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('comercializacion','comercializacion_paso3_desc','Comercialización - Paso 3 Descripción','Enviamos a todo el NEA. Si sos de Corrientes o Resistencia, recibís en el día con nuestro cadete exclusivo.','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('welcome','welcome_slide1_titulo','Inicio - Slide 1 Título','POTENCIÁ TU MEJOR VERSIÓN','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('welcome','welcome_slide2_titulo','Inicio - Slide 2 Título','CALIDAD GARANTIZADA','2026-05-28 16:49:30','2026-05-28 16:49:30'),
	 ('welcome','welcome_slide3_titulo','Inicio - Slide 3 Título','ENVÍOS A TODO EL NEA','2026-05-28 16:49:30','2026-05-28 16:49:30'),
